mapper.sql:
o.is_deleted = 0

    AND o.order_status = #{q.orderStatus}
    AND o.order_status IN (4, 5)

AND DATE(COALESCE(o.back_record_time, o.order_date)) >= #{q.dateFrom}
AND DATE(COALESCE(o.back_record_time, o.order_date)) <= #{q.dateTo}
AND o.customer_uuid = #{q.customerUuid}
AND o.settle_type = #{q.settleType}
AND o.is_invoice = #{q.isInvoice}

    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.paper_name LIKE CONCAT('%', #{q.paperName}, '%')
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.main_step_type = #{q.mainStepType}
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.process_mode = #{q.processMode}
    )


    AND EXISTS (
        SELECT 1
        FROM biz_original_roll rf
        WHERE rf.order_uuid = o.uuid
          AND rf.is_deleted = 0
          AND rf.machine_uuid = #{q.machineUuid}
    )

