) d GROUP BY d.dimensionKey, d.dimensionName ORDER BY totalAmount DESC, originalWeight DESC

SELECT d.dimensionKey, d.dimensionName, COUNT(DISTINCT d.order_uuid) AS orderCount, COUNT(DISTINCT d.original_uuid) AS originalRollCount, COALESCE(SUM(d.finishRollCount), 0) AS finishRollCount, COALESCE(SUM(d.sourceWeight), 0) AS originalWeight, COALESCE(SUM(d.finishWeight), 0) AS finishWeight, COALESCE(SUM(d.lossWeight), 0) AS lossWeight, CASE WHEN COALESCE(SUM(d.sourceWeight), 0) = 0 THEN 0 ELSE COALESCE(SUM(d.lossWeight), 0) / COALESCE(SUM(d.sourceWeight), 0) * 100 END AS lossRatio, COALESCE(SUM(d.knifeCount), 0) AS knifeCount, COALESCE(SUM(d.sawAmount), 0) AS sawAmount, COALESCE(SUM(d.rewindAmount), 0) AS rewindAmount, COALESCE(SUM(d.processAmount), 0) AS processAmount, COALESCE(SUM(d.extraAmount), 0) AS extraAmount, COALESCE(SUM(d.totalAmount), 0) AS totalAmount, COALESCE(SUM(d.settled_amount), 0) AS settled_amount, COALESCE(SUM(d.pending_settle_amount), 0) AS pending_settle_amount, COALESCE(SUM(d.receivedAmount), 0) AS receivedAmount, COALESCE(SUM(d.cashReceivedAmount), 0) AS cashReceivedAmount, COALESCE(SUM(d.scrapOffsetAmount), 0) AS scrapOffsetAmount, COALESCE(SUM(d.unreceivedAmount), 0) AS unreceivedAmount FROM ( SELECT ps.uuid AS step_uuid, ps.original_uuid, ps.order_uuid, COALESCE(ps.machine_uuid, r.machine_uuid, 'none') AS dimensionKey, COALESCE(ps.machine_name_snap, stepMachine.machine_name, rollMachine.machine_name, '未分配机台') AS dimensionName, CASE WHEN ps.step_type = 2 AND ps.process_weight IS NOT NULL THEN ps.process_weight * 1000 WHEN ps.input_type = 2 AND inputOutput.uuid IS NOT NULL THEN COALESCE(inputOutput.actual_weight, inputOutput.estimate_weight, 0) ELSE COALESCE(r.actual_weight, r.total_weight, r.roll_weight, 0) END AS sourceWeight, COALESCE(ps.loss_weight, 0) AS lossWeight, COALESCE(ps.knife_count, 0) AS knifeCount, CASE WHEN ps.step_type = 1 THEN COALESCE(ps.step_amount, 0) ELSE 0 END AS sawAmount, CASE WHEN ps.step_type = 2 THEN COALESCE(ps.step_amount, 0) ELSE 0 END AS rewindAmount, COALESCE(ps.step_amount, 0) AS processAmount, COALESCE(finalOutput.finishRollCount, 0) AS finishRollCount, COALESCE(finalOutput.finishWeight, 0) AS finishWeight, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(o.total_extra_amount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS extraAmount, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.billedAmount, o.total_amount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS totalAmount, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.billedAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS settled_amount, CASE WHEN settle.order_uuid IS NULL AND COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(o.total_amount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS pending_settle_amount, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.receivedAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS receivedAmount, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.cashReceivedAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS cashReceivedAmount, CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.scrapOffsetAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END AS scrapOffsetAmount, GREATEST( CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.billedAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END - CASE WHEN COALESCE(orderStepBase.orderStepAmount, 0) > 0 THEN COALESCE(settle.receivedAmount, 0) * COALESCE(ps.step_amount, 0) / orderStepBase.orderStepAmount ELSE 0 END, 0 ) AS unreceivedAmount FROM biz_process_step ps JOIN biz_process_order o ON o.uuid = ps.order_uuid JOIN biz_original_roll r ON r.uuid = ps.original_uuid AND r.is_deleted = 0 AND COALESCE(r.process_mode, 0) != 3 LEFT JOIN sys_machine stepMachine ON stepMachine.uuid = ps.machine_uuid LEFT JOIN sys_machine rollMachine ON rollMachine.uuid = r.machine_uuid LEFT JOIN biz_process_stage_output inputOutput ON inputOutput.uuid = ps.input_output_uuid AND inputOutput.is_deleted = 0 LEFT JOIN ( SELECT stepFinal.step_uuid, SUM(stepFinal.finishRollCount) AS finishRollCount, SUM(stepFinal.finishWeight) AS finishWeight FROM ( SELECT s.step_uuid, COUNT(DISTINCT f.uuid) AS finishRollCount, SUM(COALESCE(f.actual_weight, f.estimate_weight, 0)) AS finishWeight FROM biz_process_stage_output s JOIN biz_finish_roll f ON f.uuid = s.finish_roll_uuid AND WHERE s.is_deleted = 0 AND s.output_type = 2 AND s.output_status = 3 GROUP BY s.step_uuid UNION ALL SELECT legacyStep.uuid AS step_uuid, COUNT(DISTINCT f.uuid) AS finishRollCount, SUM(COALESCE(rel.share_weight, f.actual_weight, f.estimate_weight, 0)) AS finishWeight FROM biz_process_step legacyStep JOIN biz_finish_original_rel rel ON rel.original_uuid = legacyStep.original_uuid AND rel.is_deleted = 0 JOIN biz_finish_roll f ON f.uuid = rel.finish_uuid AND WHERE legacyStep.is_deleted = 0 AND NOT EXISTS ( SELECT 1 FROM biz_process_stage_output existingOutput WHERE existingOutput.step_uuid = legacyStep.uuid AND existingOutput.is_deleted = 0 ) GROUP BY legacyStep.uuid ) stepFinal GROUP BY stepFinal.step_uuid ) finalOutput ON finalOutput.step_uuid = ps.uuid LEFT JOIN ( SELECT psb.order_uuid, SUM(COALESCE(psb.step_amount, 0)) AS orderStepAmount FROM biz_process_step psb JOIN biz_original_roll r ON r.uuid = psb.original_uuid AND r.is_deleted = 0 AND COALESCE(r.process_mode, 0) != 3 WHERE psb.is_deleted = 0
GROUP BY psb.order_uuid ) orderStepBase ON orderStepBase.order_uuid = ps.order_uuid LEFT JOIN (
) settle ON settle.order_uuid = ps.order_uuid
ps.is_deleted = 0 AND o.is_deleted = 0
